define(["jquery","core/ajax","core/notification","core/str","core/templates"],function($,Ajax,Notification,Str,Templates){return{init:function(config){var self=this;self.config=config;self.attachEventHandlers()},attachEventHandlers:function(){var self=this;$(document).on("click",".dsl-isp-remove-dsp",function(e){e.preventDefault();var btn=$(this);var dspId=btn.data("dspid");var dspName=btn.data("dspname");self.confirmRemoveDsp(dspId,dspName)});$(document).on("click",".dsl-isp-reset-completion",function(e){e.preventDefault();var btn=$(this);var dspId=btn.data("dspid");var dspName=btn.data("dspname");self.confirmResetCompletion(dspId,dspName)})},confirmRemoveDsp:function(dspId,dspName){var self=this;Str.get_strings([{key:"confirmdspremoval",component:"local_dsl_isp",param:dspName},{key:"remove",component:"local_dsl_isp"},{key:"cancel",component:"core"}]).then(function(strings){Notification.confirm(strings[0],"",strings[1],strings[2],function(){self.removeDsp(dspId)})}).catch(Notification.exception)},removeDsp:function(dspId){var self=this;Ajax.call([{methodname:"local_dsl_isp_remove_dsp",args:{clientid:self.config.clientId,userid:dspId}}])[0].then(function(){location.reload()}).catch(Notification.exception)},confirmResetCompletion:function(dspId,dspName){var self=this;Str.get_strings([{key:"confirmresetcompletion",component:"local_dsl_isp",param:dspName},{key:"reset",component:"local_dsl_isp"},{key:"cancel",component:"core"}]).then(function(strings){Notification.confirm(strings[0],"",strings[1],strings[2],function(){self.resetCompletion(dspId)})}).catch(Notification.exception)},resetCompletion:function(dspId){var self=this;Ajax.call([{methodname:"local_dsl_isp_reset_completion",args:{clientid:self.config.clientId,userid:dspId}}])[0].then(function(){location.reload()}).catch(Notification.exception)}}});
